CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE SEQUENCE IF NOT EXISTS lis_codigo_muestra_seq START 1;
CREATE TABLE IF NOT EXISTS pacientes_lis(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_patient_id UUID UNIQUE,tipo_documento VARCHAR(10),numero_documento VARCHAR(30),primer_nombre VARCHAR(80),segundo_nombre VARCHAR(80),primer_apellido VARCHAR(80),segundo_apellido VARCHAR(80),fecha_nacimiento DATE,genero VARCHAR(10),created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS estados_orden_laboratorio(id SERIAL PRIMARY KEY,codigo VARCHAR(30) UNIQUE NOT NULL,nombre VARCHAR(80),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS secciones_laboratorio(id SERIAL PRIMARY KEY,codigo VARCHAR(30) UNIQUE NOT NULL,nombre VARCHAR(100),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS tipos_muestra(id SERIAL PRIMARY KEY,codigo VARCHAR(30) UNIQUE NOT NULL,nombre VARCHAR(100),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS pruebas_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),codigo_cups VARCHAR(30) UNIQUE NOT NULL,nombre TEXT NOT NULL,seccion_id INTEGER REFERENCES secciones_laboratorio(id),tipo_muestra_id INTEGER REFERENCES tipos_muestra(id),unidad VARCHAR(30),valor_referencia VARCHAR(100),valor_critico_min NUMERIC,valor_critico_max NUMERIC,activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS ordenes_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_order_id UUID UNIQUE,numero_orden_his VARCHAR(80),paciente_id UUID REFERENCES pacientes_lis(id),prioridad VARCHAR(30),estado_id INTEGER REFERENCES estados_orden_laboratorio(id),observaciones TEXT,payload_his JSONB,enviado_his BOOLEAN DEFAULT FALSE,enviado_his_at TIMESTAMP,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS detalle_orden_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_laboratorio(id) ON DELETE CASCADE,prueba_id UUID REFERENCES pruebas_laboratorio(id),cantidad INTEGER DEFAULT 1,UNIQUE(orden_id,prueba_id));
CREATE TABLE IF NOT EXISTS muestras_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_laboratorio(id),tipo_muestra_id INTEGER REFERENCES tipos_muestra(id),codigo_muestra VARCHAR(60) UNIQUE NOT NULL,tomada_por UUID,estado VARCHAR(30) DEFAULT 'TOMADA',created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS analizadores_laboratorio(id SERIAL PRIMARY KEY,nombre VARCHAR(100),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS procesamiento_muestras(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),muestra_id UUID REFERENCES muestras_laboratorio(id),analizador_id INTEGER REFERENCES analizadores_laboratorio(id),estado VARCHAR(30),created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS resultados_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_laboratorio(id),prueba_id UUID REFERENCES pruebas_laboratorio(id),resultado VARCHAR(120),unidad VARCHAR(30),valor_referencia VARCHAR(100),es_critico BOOLEAN DEFAULT FALSE,registrado_por UUID,validado BOOLEAN DEFAULT FALSE,created_at TIMESTAMP DEFAULT NOW(),UNIQUE(orden_id,prueba_id));
CREATE TABLE IF NOT EXISTS validaciones_resultado(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_laboratorio(id),validado_por UUID,observacion TEXT,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS reportes_laboratorio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_laboratorio(id),url_documento TEXT,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS integracion_his_lis(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_order_id UUID,lis_order_id UUID,evento VARCHAR(80),estado VARCHAR(30),payload_json JSONB,response_json JSONB,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS notificaciones_lis(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),titulo VARCHAR(150),mensaje TEXT,leida BOOLEAN DEFAULT FALSE,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS lis_menus(id SERIAL PRIMARY KEY,texto VARCHAR(80),ruta VARCHAR(120),icono_bootstrap VARCHAR(80),permiso_requerido VARCHAR(100),orden INTEGER DEFAULT 0,activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS auditoria_lis(id BIGSERIAL PRIMARY KEY,usuario_id UUID,usuario_email VARCHAR(150),accion VARCHAR(100),entidad VARCHAR(80),entidad_id UUID,ip VARCHAR(80),user_agent TEXT,detalle TEXT,created_at TIMESTAMP DEFAULT NOW());
